import azure.functions as func
import json
import logging

app = func.FunctionApp()


def add_cors_headers(headers=None):
    """Add CORS headers to response."""
    if headers is None:
        headers = {}
    headers["Access-Control-Allow-Origin"] = "*"
    headers["Access-Control-Allow-Methods"] = "GET, POST, PUT, DELETE, PATCH, OPTIONS"
    headers["Access-Control-Allow-Headers"] = "Content-Type, Authorization, X-Requested-With, Accept, Origin"
    headers["Access-Control-Max-Age"] = "86400"
    headers["Access-Control-Expose-Headers"] = "Content-Length, X-Request-Id"
    return headers


def create_response(body, status_code=200, headers=None):
    """Create an HTTP response with CORS headers."""
    cors_headers = add_cors_headers(headers or {})
    return func.HttpResponse(
        body=json.dumps(body),
        status_code=status_code,
        headers=cors_headers,
        mimetype="application/json"
    )


@app.route(route="api/health", methods=["GET", "OPTIONS"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint."""
    logging.info("Health check endpoint called.")

    if req.method == "OPTIONS":
        return create_response("", status_code=204)

    return create_response({
        "status": "healthy",
        "message": "API is running"
    })


@app.route(route="api/items", methods=["GET", "POST", "OPTIONS"], auth_level=func.AuthLevel.ANONYMOUS)
def items(req: func.HttpRequest) -> func.HttpResponse:
    """CRUD endpoint for items - supports GET (list) and POST (create)."""
    logging.info(f"Items endpoint called with method: {req.method}")

    if req.method == "OPTIONS":
        return create_response("", status_code=204)

    if req.method == "GET":
        # Example: return a list of items
        sample_items = [
            {"id": 1, "name": "Item 1", "description": "First item"},
            {"id": 2, "name": "Item 2", "description": "Second item"},
            {"id": 3, "name": "Item 3", "description": "Third item"},
        ]

        # Support query parameter filtering
        name_filter = req.params.get("name")
        if name_filter:
            sample_items = [
                item for item in sample_items
                if name_filter.lower() in item["name"].lower()
            ]

        return create_response({
            "items": sample_items,
            "count": len(sample_items)
        })

    elif req.method == "POST":
        try:
            req_body = req.get_json()
        except ValueError:
            return create_response(
                {"error": "Invalid JSON in request body"},
                status_code=400
            )

        if not req_body:
            return create_response(
                {"error": "Request body is required"},
                status_code=400
            )

        name = req_body.get("name")
        description = req_body.get("description", "")

        if not name:
            return create_response(
                {"error": "Field 'name' is required"},
                status_code=400
            )

        new_item = {
            "id": 4,  # In production, generate a real ID
            "name": name,
            "description": description
        }

        logging.info(f"Created new item: {new_item}")

        return create_response(
            {"message": "Item created successfully", "item": new_item},
            status_code=201
        )


@app.route(route="api/items/{item_id}", methods=["GET", "PUT", "DELETE", "OPTIONS"], auth_level=func.AuthLevel.ANONYMOUS)
def item_by_id(req: func.HttpRequest) -> func.HttpResponse:
    """CRUD endpoint for a single item by ID."""
    logging.info(f"Item by ID endpoint called with method: {req.method}")

    if req.method == "OPTIONS":
        return create_response("", status_code=204)

    item_id = req.route_params.get("item_id")

    if not item_id:
        return create_response(
            {"error": "Item ID is required"},
            status_code=400
        )

    try:
        item_id = int(item_id)
    except ValueError:
        return create_response(
            {"error": "Item ID must be an integer"},
            status_code=400
        )

    # Sample data store (in production, use a database)
    sample_items = {
        1: {"id": 1, "name": "Item 1", "description": "First item"},
        2: {"id": 2, "name": "Item 2", "description": "Second item"},
        3: {"id": 3, "name": "Item 3", "description": "Third item"},
    }

    if req.method == "GET":
        item = sample_items.get(item_id)
        if not item:
            return create_response(
                {"error": f"Item with ID {item_id} not found"},
                status_code=404
            )
        return create_response({"item": item})

    elif req.method == "PUT":
        if item_id not in sample_items:
            return create_response(
                {"error": f"Item with ID {item_id} not found"},
                status_code=404
            )

        try:
            req_body = req.get_json()
        except ValueError:
            return create_response(
                {"error": "Invalid JSON in request body"},
                status_code=400
            )

        if not req_body:
            return create_response(
                {"error": "Request body is required"},
                status_code=400
            )

        updated_item = {
            "id": item_id,
            "name": req_body.get("name", sample_items[item_id]["name"]),
            "description": req_body.get("description", sample_items[item_id]["description"])
        }

        logging.info(f"Updated item: {updated_item}")

        return create_response({
            "message": "Item updated successfully",
            "item": updated_item
        })

    elif req.method == "DELETE":
        if item_id not in sample_items:
            return create_response(
                {"error": f"Item with ID {item_id} not found"},
                status_code=404
            )

        logging.info(f"Deleted item with ID: {item_id}")

        return create_response({
            "message": f"Item with ID {item_id} deleted successfully"
        })


